import com.pinterest.ktlint.rule.engine.core.api.IndentConfig
import com.pinterest.ktlint.test.assertThatRule
import org.junit.jupiter.api.Test

/**
 * Test for the fix of the issue where lines starting with '||' cause an internal error.
 * The issue was in the isElvisOperator() method which didn't handle null firstChildNode safely.
 */
class ElvisOperatorNullabilityTest {
    @Test
    fun `Given code with lines starting with or operator should not crash`() {
        val code =
            """
            package com.my.lint.rules

            import com.pinterest.ktlint.rule.engine.core.api.Rule
            import com.pinterest.ktlint.rule.engine.core.api.RuleId
            import org.jetbrains.kotlin.com.intellij.lang.ASTNode

            class BreakKtlintFormatRule : Rule(
                RuleId("my-ruleset:my-rule-id"),
                Rule.About(maintainer = "Me", repositoryUrl = "repositoryUrl", issueTrackerUrl = "issueTrackerUrl")
            ) {
                override fun beforeVisitChildNodes(
                    node: ASTNode,
                    autoCorrect: Boolean,
                    emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit
                ) {
                    if (node.text.contains("this")
                        || node.text.contains("that")
                    ) {
                        emit(node.startOffset, "My violation detail", false)
                    }
                }
            }
            """.trimIndent()

        // This test verifies that the fix handles null firstChildNode correctly
        // and doesn't throw NullPointerException
        val result = assertThatRule { IndentationRule() }
            .withEditorConfigOverrides(
                mapOf(
                    "indent_style" to "space",
                    "indent_size" to "4",
                ),
            )
            .allowToBeAutoFormatted()
            .asLintResult()
            .forCode(code)

        // The test passes if no exception is thrown during processing
        // The specific formatting result doesn't matter - we just need to ensure no crash
    }
}"}

